#!/bin/bash
# Generated by OrchestKit Claude Plugin
# Created: 2026-05-02

# Integration test: cc-release-watch.mjs end-to-end against synthetic fixture.
# Verifies snapshot writes, gap report shape, idempotence, and issue-args emission.
# No network, no LLM, no actual gh issue create — pure file-system effects.
# Issue: #1486 (M130)

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../.." && pwd)"

RED='\033[0;31m'
GREEN='\033[0;32m'
NC='\033[0m'

PASS=0
FAIL=0
log_pass() { echo -e "  ${GREEN}✓${NC} $1"; PASS=$((PASS + 1)); }
log_fail() { echo -e "  ${RED}✗${NC} $1 — $2"; FAIL=$((FAIL + 1)); }

echo "CC Release Watch Tests (M130 #1486)"
echo "==================================="

cd "$PROJECT_ROOT"

# Save state we'll mutate during tests. Errors during backup are real (FS issue, perm denied)
# and should fail the test rather than be hidden.
SNAPSHOTS_BACKUP=$(mktemp -d)
if [ -d shared/cc-snapshots ]; then
  # rsync rather than cp -r/. so we don't need shell-glob expansion of dotfiles.
  rsync -a shared/cc-snapshots/ "$SNAPSHOTS_BACKUP/"
fi
GAPS_BACKUP=""
[ -f shared/cc-adoption-gaps.json ] && GAPS_BACKUP=$(cat shared/cc-adoption-gaps.json)
ARGS_BACKUP=""
[ -f shared/gh-issue-args.json ] && ARGS_BACKUP=$(cat shared/gh-issue-args.json)

restore() {
  rm -rf shared/cc-snapshots
  mkdir -p shared/cc-snapshots
  if [ -d "$SNAPSHOTS_BACKUP" ] && [ -n "$(ls -A "$SNAPSHOTS_BACKUP" 2>&1)" ]; then
    rsync -a "$SNAPSHOTS_BACKUP/" shared/cc-snapshots/
  fi
  rm -rf "$SNAPSHOTS_BACKUP"
  if [ -n "$GAPS_BACKUP" ]; then
    echo "$GAPS_BACKUP" > shared/cc-adoption-gaps.json
  else
    rm -f shared/cc-adoption-gaps.json
  fi
  if [ -n "$ARGS_BACKUP" ]; then
    echo "$ARGS_BACKUP" > shared/gh-issue-args.json
  else
    rm -f shared/gh-issue-args.json
  fi
}
trap restore EXIT

# Reset to clean state for tests
rm -rf shared/cc-snapshots/*.md shared/cc-adoption-gaps.json shared/gh-issue-args.json

# Pre-populate snapshots for every prior version that's <= cc-support.json.latest
# to simulate the production steady state. This isolates Test 1 to the "one new
# version" scenario (2.1.170 — the synthetic fixture's top version, the only
# entry NOT in the pre-populated snapshot set below) without triggering the
# M130-hotfix recovery path that re-snapshots equal-version-but-missing-on-disk
# entries (covered by Test 4 below). The fixture's top version tracks
# cc-support.json.latest (currently 2.1.170) so Test 4's recovery target — which
# reads `.latest` — finds a matching changelog entry; bump both together.
mkdir -p shared/cc-snapshots
for v in 2.1.126 2.1.127 2.1.128 2.1.129 2.1.131 2.1.132 2.1.133 2.1.136 2.1.137 2.1.138; do
  echo "# Claude Code $v (placeholder for test)" > "shared/cc-snapshots/$v.md"
done

# ============================================================================
# Test 1: fixture with one new version → writes snapshot + gaps + args
# ============================================================================
CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/synthetic.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-out.txt 2>&1

if [ -f shared/cc-snapshots/2.1.170.md ]; then
  log_pass "Snapshot written for new version 2.1.170"
else
  log_fail "Snapshot missing" "expected shared/cc-snapshots/2.1.170.md (see /tmp/watch-out.txt)"
fi

if [ -f shared/cc-snapshots/2.1.170.md ] && grep -qF "EnterWorktree" shared/cc-snapshots/2.1.170.md; then
  log_pass "Snapshot body contains expected feature bullet"
else
  log_fail "Snapshot body" "missing 'EnterWorktree' from fixture"
fi

if [ -f shared/cc-adoption-gaps.json ]; then
  COUNT=$(jq 'length' shared/cc-adoption-gaps.json)
  if [ "$COUNT" = "1" ]; then
    log_pass "Gaps JSON has exactly 1 entry"
    GAP_VERSION=$(jq -r '.[0].version' shared/cc-adoption-gaps.json)
    if [ "$GAP_VERSION" = "2.1.170" ]; then
      log_pass "Gap entry version = 2.1.170"
    else
      log_fail "Gap entry version" "expected 2.1.170, got '$GAP_VERSION'"
    fi
  else
    log_fail "Gaps JSON entry count" "expected 1, got $COUNT"
  fi
else
  log_fail "Gaps JSON" "shared/cc-adoption-gaps.json was not written"
fi

if [ -f shared/gh-issue-args.json ]; then
  TITLE=$(jq -r '.milestone' shared/gh-issue-args.json)
  # Single rolling umbrella: the milestone title is now CONSTANT across
  # versions ("CC adoption"), not "CC X.Y.Z adoption" per version.
  if [ "$TITLE" = "CC adoption" ]; then
    log_pass "gh-issue-args milestone title = 'CC adoption' (single rolling umbrella)"
  else
    log_fail "milestone title" "expected 'CC adoption', got '$TITLE'"
  fi
  # Per-version traceability is preserved in latest_new_version even though
  # the milestone no longer encodes the version.
  LATEST=$(jq -r '.latest_new_version' shared/gh-issue-args.json)
  if [ "$LATEST" = "2.1.170" ]; then
    log_pass "gh-issue-args latest_new_version = 2.1.170 (per-version trace kept)"
  else
    log_fail "latest_new_version" "expected 2.1.170, got '$LATEST'"
  fi
else
  log_fail "gh-issue-args.json missing" "expected emitted by watch script"
fi

# ============================================================================
# Test 2: idempotent — re-running with same fixture produces no-op
# ============================================================================
CC_RELEASE_WATCH_FIXTURE=tests/fixtures/cc-changelogs/synthetic.md \
  node scripts/cc-release-watch.mjs > /tmp/watch-out2.txt 2>&1

if grep -qF "nothing new" /tmp/watch-out2.txt; then
  log_pass "Idempotent on second run with same fixture"
else
  log_fail "Idempotent check" "expected 'nothing new', got: $(tail -2 /tmp/watch-out2.txt)"
fi

# After Test 1, the 2.1.170 gap entry is un-triaged (empty features) and
# UN-stamped (no issues_filed_at) — i.e. un-filed work. The carry-forward fix
# (#2084 follow-up) intentionally PRESERVES such entries across a no-op run
# instead of clearing them: the old "clear to []" behavior silently dropped
# un-filed work, which is the straggler class this fix closes. In production the
# filer stamps issues_filed_at before the next watch run, so a fully-processed
# entry IS still pruned — proven by Test 12 below.
if [ -f shared/cc-adoption-gaps.json ]; then
  KEPT=$(jq -r '[.[] | select(.version=="2.1.170" and (has("issues_filed_at")|not))] | length' shared/cc-adoption-gaps.json)
  if [ "$KEPT" = "1" ]; then
    log_pass "No-op run preserves un-filed (un-stamped) gap entry (carry-forward, #2084 fix)"
  else
    log_fail "Idempotent gaps carry" "expected un-stamped 2.1.170 preserved on no-op run, got $KEPT"
  fi
fi

# ============================================================================
# Test 3: snapshot file persists across no-op runs
# ============================================================================
if [ -f shared/cc-snapshots/2.1.128.md ]; then
  log_pass "Snapshot persists across no-op runs"
else
